THE CLAIM:
{
 "title": "Big-operator sales locked up by global contracts, out of reach",
 "narrative": "The model gives large operators 40% of buyer spend and plans to sell to them first. But hyperscalers and pan-European colos like Equinix and Digital Realty pick rack-PDU vendors through global contracts signed at headquarters on multi-year cycles. A Central European regional team cannot reach that spend in 12 months, so the Year-1 pipeline is built on buyers the venture cannot access.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Big operators buy PDUs through global vendor lists and contracts.",
   "refs": [
    "digest:cust-mix#c9",
    "digest:cust-mix#c0"
   ]
  },
  {
   "step": "propagation",
   "text": "The 40% share rests on one supplier's order stat, not channel data.",
   "refs": [
    "ledger:cust.operator-large",
    "digest:cust-mix#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "This buyer cell is closed, yet the first-sale strategy targets it.",
   "refs": [
    "profile:Who is the primary buyer you'll sell through first?",
    "ledger:cust.operator-large"
   ]
  }
 ],
 "falsifier": "Two or more Central European large operators confirming country-level PDU sourcing power, plus a documented case of a new vendor entering their approved list via a regional pilot within 12 months.",
 "category": "competitive",
 "evidence": [
  {
   "title": "Vertiv Partner Program EMEA — Major Customers list",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone",
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "attached": true
  },
  {
   "title": "Global Data Center Supplier Risk Management (Google/Achilles)",
   "sourceType": "industry-report",
   "publisher": "Achilles",
   "date": "2026-03-06",
   "excerpt": "Google's Data Center Construction Program team uses Achilles to scale its global data center construction program... streamlines supplier intake, prequalification, and risk visibility, enabling faster, data-driven procurement decisions",
   "url": "https://www.achilles.com/industry-insights/google/",
   "attached": true
  },
  {
   "title": "Greenergy and A-Kaabel deploy Vertiv rack PDUs in Estonia",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "Now Estonia's leading colocation provider, Greenergy targets HPC and AI customers with IT loads exceeding 10 MW... Supporting this evolution is A-Kaabel OÜ... an authorized sales and service partner for Vertiv in Estonia.",
   "url": "https://www.vertiv.com/48ebb0/globalassets/documents/case-studies/vertiv-greenergy-cs-en-emea-web.pdf",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "cust.operator-large",
  "label": "Large operators",
  "kind": "estimated",
  "value": 0.4,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": "customerType",
  "dimensionValue": "operator-large",
  "sensitivityRange": {
   "low": 0.33,
   "high": 0.47
  },
  "funnelActive": true,
  "derivation": {
   "method": "Qualitative channel triangulation",
   "expression": "Hyperscale+colo ≈ 62% of capacity (Synergy) and large operators buy direct → dominant buyer ≈ 0.40 of PDU spend"
  },
  "provenance": {
   "rationale": "Report segmentations name the channels (direct/OEM/distributor) but publish no percentages → internal estimate.",
   "promotionPath": "Validate buyer mix with 3 CE operator/distributor interviews."
  },
  "evidence": [
   {
    "title": "Data center growth driving power equipment sales",
    "sourceType": "analyst-estimate",
    "publisher": "Alexander Group",
    "date": "2026-06-19",
    "excerpt": "One leading supplier reported data centers as its biggest growth driver, accounting for 30% of orders in 2025 — qualitative channel context only.",
    "attached": true
   },
   {
    "title": "CE operator & distributor interviews",
    "sourceType": "pending",
    "publisher": null,
    "date": null,
    "excerpt": "Three structured interviews would replace this qualitative split with a sourced one.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
